module calendar(
    input CLK,
    input RST,
    output reg [5:0] Hours,
    output reg [5:0] Mins,
    output reg [5:0] Secs
);
  parameter MAX_SECONDS = 59;
  parameter MAX_MINUTES = 59;
  parameter MAX_HOURS = 23;
  always @(posedge CLK or posedge RST) begin
    if (RST) begin
      Secs <= 0;
    end else begin
      if (Secs == MAX_SECONDS) begin
        Secs <= 0;
      end else begin
        Secs <= Secs + 1;
      end
    end
  end
  always @(posedge CLK or posedge RST) begin
    if (RST) begin
      Mins <= 0;
    end else begin
      if (Secs == MAX_SECONDS && Mins == MAX_MINUTES) begin
        Mins <= 0;
      end else if (Secs == MAX_SECONDS) begin
        Mins <= Mins + 1;
      end else begin
        Mins <= Mins;
      end
    end
  end
  always @(posedge CLK or posedge RST) begin
    if (RST) begin
      Hours <= 0;
    end else begin
      if (Secs == MAX_SECONDS && Mins == MAX_MINUTES && Hours == MAX_HOURS) begin
        Hours <= 0;
      end else if (Secs == MAX_SECONDS && Mins == MAX_MINUTES) begin
        Hours <= Hours + 1;
      end else begin
        Hours <= Hours;
      end
    end
  end
endmodule
